const translations=baseTranslations;

const globalProgressData=[
  {key:'completed',value:128,color:'#079455'},
  {key:'process',value:46,color:'#1570ef'},
  {key:'waiting',value:18,color:'#dc6803'},
  {key:'cancelled',value:7,color:'#d92d20'}
];
function renderGlobalProgress(){const grid=$('#globalStatsGrid'),donut=$('#globalDonutChart'),totalEl=$('#globalTotalFiles');if(!grid||!donut||!totalEl)return;const total=globalProgressData.reduce((sum,item)=>sum+item.value,0);totalEl.textContent=total;let current=0;const segments=globalProgressData.map(item=>{const start=current;const end=current+(item.value/total)*100;current=end;return `${item.color} ${start}% ${end}%`}).join(', ');donut.style.background=`conic-gradient(${segments})`;grid.innerHTML=globalProgressData.map(item=>{const pct=Math.round((item.value/total)*100);return `<article class="stat-card ${item.key}"><span style="--stat-color:${item.color}"></span><div><strong>${item.value}</strong><p>${t('documents.'+item.key)}</p><small>${pct}% ${t('documents.percent')}</small></div></article>`}).join('')}

const defaultOfficeSettings={officeType:'KANTOR NOTARIS/PPAT',officeName:'NI LUH PUTU SURYA MIRA YANTI, SH., M.Kn.',profileRole:'Notaris dan PPAT',whatsapp:'+62 812-3456-7890',phone:'(0361) 000-000',email:'info@notarissuryamira.co.id',address:'Jl. Raya Utama No. 123, Bali, Indonesia',hours:'Senin - Jumat, 09.00 - 16.00 WITA'};let officeSettings={...defaultOfficeSettings,...JSON.parse(localStorage.getItem('officeSettings')||'{}')};let lang=localStorage.getItem('publicLang')||'id';let activeFilter='all';let currentStep=1;let loggedIn=localStorage.getItem('settingsLoggedIn')==='true';let currentView=localStorage.getItem('publicView')||'auto';let currentTheme=localStorage.getItem('publicTheme')||'light';const $=s=>document.querySelector(s);const $$=s=>[...document.querySelectorAll(s)];const t=k=>k.split('.').reduce((o,p)=>o?.[p],translations[lang])||k;

function getResolvedView(){if(currentView!=='auto')return currentView;return window.innerWidth<700?'phone':window.innerWidth<1100?'tablet':'desktop'}
function applyDisplayMode(){document.documentElement.dataset.view=getResolvedView();document.documentElement.dataset.viewPreference=currentView;$$('[data-view-btn]').forEach(b=>b.classList.toggle('active',b.dataset.viewBtn===currentView))}

function applyTheme(){document.documentElement.dataset.theme=currentTheme;$$('[data-theme-btn]').forEach(b=>b.classList.toggle('active',b.dataset.themeBtn===currentTheme))}
function setTheme(nextTheme){currentTheme=nextTheme;localStorage.setItem('publicTheme',currentTheme);applyTheme()}

function applyAuthState(){const auth=$('[data-auth-btn]');if(auth)auth.textContent=loggedIn?(lang==='id'?'Logout':'Logout'):(lang==='id'?'Login':'Login')}
function setLanguage(nextLang){lang=nextLang;localStorage.setItem('publicLang',lang);applyTranslations()}
function setDisplayMode(nextView){currentView=nextView;localStorage.setItem('publicView',currentView);applyDisplayMode()}
function openLoginModal(){const modal=$('#loginModal');if(!modal)return;document.body.classList.add('login-open');modal.classList.add('open');modal.setAttribute('aria-hidden','false');setTimeout(()=>modal.classList.add('show-form'),950)}function closeLoginModal(){const modal=$('#loginModal');if(!modal)return;modal.classList.remove('show-form');modal.classList.remove('open');modal.setAttribute('aria-hidden','true');document.body.classList.remove('login-open')}function togglePublicAuth(){if(loggedIn){loggedIn=false;localStorage.setItem('settingsLoggedIn',String(loggedIn));applyAuthState();return}openLoginModal()}

function serviceName(s){return s[lang]||s.id}function categoryName(c){return c==='notary'?t('services.categoryNotary'):t('services.categoryPpat')}function getFlow(key){let f=flowData[key];if(f?.alias)f=flowData[f.alias];return f||{id:genericId,en:genericEn}}function flowSteps(key){const f=getFlow(key);return f[lang]||f.id}

function applyOfficeSettings(){
  document.querySelectorAll('[data-i18n="office.type"]').forEach(el=>el.textContent=officeSettings.officeType);
  document.querySelectorAll('[data-i18n="office.name"]').forEach(el=>el.textContent=officeSettings.officeName);
  document.querySelectorAll('[data-i18n="profile.name"]').forEach(el=>el.textContent=officeSettings.officeName);
  document.querySelectorAll('[data-i18n="profile.role"]').forEach(el=>el.textContent=officeSettings.profileRole);
  document.querySelectorAll('a[href^="https://wa.me/"]').forEach(el=>el.href='https://wa.me/'+officeSettings.whatsapp.replace(/\D/g,''));
  document.querySelectorAll('.premium-contact-grid article').forEach(card=>{
    const label=card.querySelector('span')?.textContent||'';
    const strong=card.querySelector('strong');
    if(!strong)return;
    if(label.toLowerCase().includes('whatsapp'))strong.textContent=officeSettings.whatsapp;
    if(label.toLowerCase().includes('telepon')||label.toLowerCase().includes('phone'))strong.textContent=officeSettings.phone;
    if(label.toLowerCase().includes('email'))strong.textContent=officeSettings.email;
    if(label.toLowerCase().includes('jam')||label.toLowerCase().includes('hours'))strong.textContent=officeSettings.hours;
  });
  const addressText=document.querySelector('[data-i18n="address.full"]');if(addressText)addressText.textContent=officeSettings.address;
  const hoursText=document.querySelector('[data-i18n="address.hours"]');if(hoursText)hoursText.textContent=(lang==='id'?'Jam operasional: ':'Operating hours: ')+officeSettings.hours;
  document.querySelectorAll('[data-setting-field]').forEach(input=>{if(officeSettings[input.dataset.settingField]!==undefined)input.value=officeSettings[input.dataset.settingField]});
  const panel=$('[data-profile-panel]');if(panel)panel.hidden=!loggedIn||!panel.dataset.open;
  const profileBtn=$('.profile-settings');if(profileBtn)profileBtn.disabled=!loggedIn;
}
function saveOfficeSettings(){document.querySelectorAll('[data-setting-field]').forEach(input=>officeSettings[input.dataset.settingField]=input.value.trim()||defaultOfficeSettings[input.dataset.settingField]||'');localStorage.setItem('officeSettings',JSON.stringify(officeSettings));applyTranslations();const msg=$('[data-settings-message]');if(msg){msg.textContent=t('settings.saved');msg.hidden=false;setTimeout(()=>msg.hidden=true,2400)}}
function resetOfficeSettings(){officeSettings={...defaultOfficeSettings};localStorage.removeItem('officeSettings');applyTranslations()}

window.toggleSettingsAuth=togglePublicAuth;
window.setPublicLanguage=setLanguage;
window.setPublicView=setDisplayMode;
window.setPublicTheme=setTheme;

function applyTranslations(){document.documentElement.lang=lang;document.documentElement.dataset.lang=lang;$$('[data-i18n]').forEach(el=>el.textContent=t(el.dataset.i18n));$$('[data-i18n-placeholder]').forEach(el=>el.placeholder=t(el.dataset.i18nPlaceholder));renderGlobalProgress();renderServiceCatalog();renderTransactionOptions();renderSteps();renderSummary();$$('[data-lang-btn]').forEach(b=>b.classList.toggle('active',b.dataset.langBtn===lang));const auth=$('[data-auth-btn]');if(auth)auth.textContent=loggedIn?(lang==='id'?'Logout':'Logout'):(lang==='id'?'Login':'Login');$$('[data-view-btn]').forEach(b=>b.classList.toggle('active',b.dataset.viewBtn===currentView));applyDisplayMode();applyTheme();window.addEventListener('resize',()=>{if(currentView==='auto')applyDisplayMode()});applyAuthState()}
function renderServiceCatalog(){const box=$('#serviceCatalog');if(!box)return;const items=serviceCatalog.filter(s=>activeFilter==='all'||s.category===activeFilter);const cards=items.map(s=>`<article class="service-item"><div><span class="service-badge">${categoryName(s.category)}</span><h3>${serviceName(s)}</h3><p>${s.category==='notary'?t('services.descNotary'):t('services.descPpat')}</p></div><div class="service-actions"><button type="button" class="primary-btn" data-register-service="${s.key}">${t('services.register')}</button><button type="button" class="secondary-btn" data-process-service="${s.key}">${t('services.process')}</button></div></article>`).join('');box.innerHTML=`<div class="service-marquee"><div class="service-track">${cards}${cards}</div></div>`}
function renderTransactionOptions(){const opt=$('[data-options="transactions"]');if(!opt)return;opt.innerHTML=serviceCatalog.map((s,i)=>`<label class="choice"><input type="radio" name="transaction" value="${serviceName(s)}" data-service-key="${s.key}" ${i===0?'checked':''}> ${serviceName(s)}</label>`).join('');syncSelectedService()}
function syncSelectedService(key){const checked=$('input[name="transaction"]:checked');const selected=key?serviceCatalog.find(s=>s.key===key):serviceCatalog.find(s=>s.key===checked?.dataset.serviceKey);if(!selected)return;$('#selectedServiceKey').value=selected.key;$('#selectedServiceName').value=serviceName(selected)}
function chooseService(key,scroll=true){const service=serviceCatalog.find(s=>s.key===key);if(!service)return;document.querySelectorAll('input[name="transaction"]').forEach(r=>{r.checked=r.dataset.serviceKey===key});syncSelectedService(key);renderSummary();if(scroll){const target=document.querySelector('#pendaftaran');if(target)target.scrollIntoView({behavior:'smooth',block:'start'})}}
function openProcess(key){const service=serviceCatalog.find(s=>s.key===key);if(!service)return;$('#processCategory').textContent=categoryName(service.category);$('#processTitle').textContent=serviceName(service);$('#processSteps').innerHTML=flowSteps(key).map((step,i)=>`<div class="process-step"><span>${i+1}</span><p>${step}</p></div>`).join('');$('#processModal').classList.add('open');$('#processModal').setAttribute('aria-hidden','false')}


function openTrackingModal(){const modal=$('#trackingModal');if(!modal)return;modal.classList.add('open');modal.setAttribute('aria-hidden','false');setTimeout(()=>$('#trackingCode')?.focus(),50)}
function closeTrackingModal(){const modal=$('#trackingModal');if(!modal)return;modal.classList.remove('open');modal.setAttribute('aria-hidden','true')}

function renderSteps(){const steps=$('#wizardSteps');if(steps)steps.innerHTML=[1,2,3,4,5].map(n=>`<div class="step-chip ${n===currentStep?'active':''}">${n}</div>`).join('')}
function showStep(step){if(!$('#registrationForm'))return;currentStep=step;$$('.wizard-panel').forEach(p=>p.hidden=Number(p.dataset.step)!==currentStep);const prev=$('#prevStep'),next=$('#nextStep'),submit=$('#submitRegistration'),errors=$('#formErrors');if(prev)prev.style.display=currentStep===1?'none':'inline-flex';if(next)next.hidden=currentStep===5;if(submit)submit.hidden=currentStep!==5;renderSteps();renderSummary();if(errors)errors.textContent=''}
function addParty(type){const wrap=$(`#${type}Parties`);if(!wrap)return;const input=document.createElement('input');input.name=`${type}Party[]`;input.required=true;input.placeholder=lang==='id'?'Nama pihak':'Party name';input.style.marginBottom='10px';wrap.appendChild(input)}
function validateStep(){const form=$('#registrationForm');$$('.invalid').forEach(e=>e.classList.remove('invalid'));let errors=[];if(currentStep===2){['fullName','ktp','whatsapp','email','address','actingAs'].forEach(n=>{const el=form.elements[n];if(!el.value.trim()){el.classList.add('invalid');errors.push(t('registration.required'))}});if(form.whatsapp.value&&!/^\+?\d{9,15}$/.test(form.whatsapp.value.replace(/[\s-]/g,''))){form.whatsapp.classList.add('invalid');errors.push(lang==='id'?'Nomor WhatsApp harus valid.':'WhatsApp number must be valid.')}if(form.email.value&&!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email.value)){form.email.classList.add('invalid');errors.push(lang==='id'?'Email harus valid.':'Email must be valid.')}}if(currentStep===3){['firstParties','secondParties'].forEach(id=>{if(!$(`#${id} input`)?.value?.trim())errors.push(t('registration.required'))})}if(currentStep===4){$$('input[type=file]').forEach(input=>{if(input.files[0]){const f=input.files[0],ok=['application/pdf','image/jpeg','image/png'].includes(f.type)||/\.(pdf|jpg|jpeg|png)$/i.test(f.name);if(!ok||f.size>2*1024*1024){input.classList.add('invalid');errors.push(lang==='id'?'File harus PDF, JPG, JPEG, atau PNG maksimal 2 MB.':'Files must be PDF, JPG, JPEG, or PNG maximum 2 MB.')}}})}errors=[...new Set(errors)];$('#formErrors').innerHTML=errors.map(e=>`<p>${e}</p>`).join('');return errors.length===0}
function renderSummary(){const box=$('#summaryBox');if(!box)return;const form=$('#registrationForm');const data=new FormData(form);syncSelectedService();const rows=[[t('registration.selectedService'),data.get('service_name')],['Nama',data.get('fullName')],['KTP',data.get('ktp')],['WhatsApp',data.get('whatsapp')],['Email',data.get('email')],['Alamat',data.get('address')]].filter(r=>r[1]);box.innerHTML=rows.length?rows.map(([a,b])=>`<p><strong>${a}:</strong> ${b}</p>`).join(''):`<p>${t('registration.required')}</p>`}
const trackingRecords={'TRK-2026-0001':{service:'jualbeli',applicant:'Komang Arya Pratama',fileNo:'BRK-2026-014',current:8,registered:'10 Juni 2026',note:'Berkas sudah masuk tahap penandatanganan AJB. Mohon pemohon menunggu konfirmasi jadwal tanda tangan dari petugas kantor.',dates:{1:'10 Jun 2026, 09:15',2:'11 Jun 2026, 10:20',3:'12 Jun 2026, 14:05',4:'13 Jun 2026, 11:30',5:'14 Jun 2026, 15:10',6:'15 Jun 2026, 09:45',7:'17 Jun 2026, 13:25',8:'18 Jun 2026, 10:00'}},'TRK-2026-0002':{service:'hibah',applicant:'Ni Made Sari',fileNo:'BRK-2026-021',current:4,registered:'12 Juni 2026',special:'waiting',note:'Proses sementara ditahan karena SPPT PBB terbaru belum diterima. Mohon kirim dokumen pelengkap melalui WhatsApp kantor atau datang langsung ke kantor.',dates:{1:'12 Jun 2026, 09:00',2:'13 Jun 2026, 10:30',3:'14 Jun 2026, 14:45'}},'TRK-2026-0003':{service:'roya',applicant:'I Wayan Dana',fileNo:'BRK-2026-025',current:8,registered:'02 Juni 2026',completed:'09 Juni 2026',note:'Dokumen roya sudah selesai. Pemohon dapat mengambil dokumen pada jam pelayanan dengan membawa identitas asli dan kode tracking.',dates:{1:'02 Jun 2026, 08:55',2:'03 Jun 2026, 11:10',3:'04 Jun 2026, 09:40',4:'05 Jun 2026, 13:15',5:'07 Jun 2026, 10:05',6:'08 Jun 2026, 14:20',7:'09 Jun 2026, 09:30',8:'09 Jun 2026, 15:00'}},'TRK-2026-0004':{service:'sewa',applicant:'PT Bali Sejahtera',fileNo:'BRK-2026-030',current:3,registered:'15 Juni 2026',special:'cancelled',note:'Berkas dibatalkan atas permintaan pemohon. Jika ingin melanjutkan kembali, silakan ajukan pendaftaran ulang atau hubungi admin kantor.',dates:{1:'15 Jun 2026, 10:15',2:'16 Jun 2026, 11:00'}}};
function trackingHtml(record){const service=serviceCatalog.find(s=>s.key===record.service)||serviceCatalog[0];const steps=flowSteps(record.service);const special=record.special;const currentText=special==='waiting'?t('tracking.waiting'):special==='cancelled'?t('tracking.cancelled'):steps[record.current-1];const stateLabel=state=>state==='done'?t('tracking.done'):state==='running'?t('tracking.running'):state==='waiting'?t('tracking.waiting'):state==='cancelled'?t('tracking.cancelled'):t('tracking.pending');const timeline=steps.map((step,i)=>{const n=i+1;let state=n<record.current?'done':n===record.current?'running':'pending';if(special==='cancelled'&&n===record.current)state='cancelled';if(special==='waiting'&&n===record.current)state='waiting';const estimate=7+((n*3)%12);const meta=state==='done'?(record.dates[n]||'-'):(state==='running'||state==='waiting'?`${t('tracking.estimate')}: ${estimate}-${estimate+4} ${t('tracking.workDays')}`:stateLabel(state));return `<div class="track-step ${state}"><b><span>${state==='done'?'OK':n}</span></b><div class="track-step-copy"><strong>${n}. ${step}</strong><small>${stateLabel(state)}</small></div><time>${meta}</time></div>`}).join('');return `<section class="tracking-summary-card"><header><span>${t('tracking.fileNo')}</span><strong>${record.fileNo}</strong></header><div class="tracking-detail-row person"><i></i><div><small>${t('tracking.applicant')}</small><b>${record.applicant}</b></div></div><div class="tracking-detail-row document"><i></i><div><small>${t('tracking.transaction')}</small><b>${serviceName(service)}</b></div></div><div class="tracking-detail-row status"><i></i><div><small>${t('tracking.current')}</small><b><span class="status-pill ${special||'running'}">${currentText}</span></b></div></div><div class="tracking-detail-row calendar"><i></i><div><small>${t('tracking.date')}</small><b>${record.registered}</b></div></div>${record.completed?`<div class="tracking-detail-row calendar"><i></i><div><small>${t('tracking.completedDate')}</small><b>${record.completed}</b></div></div>`:''}</section><section class="tracking-progress-card"><h3>${lang==='id'?'Progres Tahapan':'Stage Progress'}</h3><div class="tracking-stepper">${timeline}</div></section><section class="admin-note-card"><h3>${t('tracking.note')}</h3><div><i></i><p>${record.note}</p></div></section>${record.completed?`<button type="button" class="primary-btn pickup-btn">${t('tracking.pickup')}</button><p class="pickup-info">${t('tracking.pickupInfo')}</p>`:''}`}function initLegacySections(){const docGrid=$('.documents-grid');if(docGrid&&!docGrid.children.length)docGrid.innerHTML=['Jual Beli','Hibah','Waris','Balik Nama','Roya','APHT','SKMHT','Pendirian PT/CV/Yayasan','Legalisasi','Waarmerking','Akta Perjanjian','Akta Kuasa'].map(x=>`<article class="doc-card"><i>?</i><strong>${x}</strong></article>`).join('');const uploads=$('#documentChecklist');if(uploads&&!uploads.children.length)uploads.innerHTML=['KTP','KK','NPWP','Sertifikat','SPPT PBB','Akta nikah','Akta PT','SK Kemenkumham','Surat kuasa','Dokumen pendukung lainnya'].map((d,i)=>`<label><span>${d}</span><input type="file" name="doc${i}" accept=".pdf,.jpg,.jpeg,.png"></label>`).join('')}
document.addEventListener('DOMContentLoaded',()=>{initLegacySections();applyTranslations();if($('#registrationForm')){addParty('first');addParty('second');showStep(1);}$('.hamburger')?.addEventListener('click',()=>$('.main-nav').classList.toggle('open'));$$('[data-lang-btn]').forEach(b=>b.addEventListener('click',()=>setLanguage(b.dataset.langBtn)));applyDisplayMode();applyTheme();$$('[data-view-btn]').forEach(b=>b.addEventListener('click',()=>setDisplayMode(b.dataset.viewBtn)));$$('[data-theme-btn]').forEach(b=>b.addEventListener('click',()=>setTheme(b.dataset.themeBtn)));$('[data-auth-btn]')?.addEventListener('click',()=>togglePublicAuth());document.addEventListener('click',e=>{const settingsToggle=e.target.closest('.settings-toggle');if(settingsToggle){e.preventDefault();const panel=$('.settings-panel');document.body.classList.add('settings-open');panel?.classList.add('open');panel?.setAttribute('aria-hidden','false');return}if(e.target.closest('.settings-close')||e.target.classList.contains('settings-panel')){const panel=$('.settings-panel');document.body.classList.remove('settings-open');document.body.classList.remove('settings-open');panel?.classList.remove('open');panel?.setAttribute('aria-hidden','true');return}const authClick=e.target.closest('[data-auth-btn]');if(authClick){togglePublicAuth();return}const trackingLink=e.target.closest('a[href="#tracking"]');if(trackingLink){e.preventDefault();openTrackingModal();return}if(e.target.matches('[data-close-tracking]')||e.target.id==='trackingModal'){closeTrackingModal();return}const reg=e.target.closest('[data-register-service]');if(reg)chooseService(reg.dataset.registerService);const proc=e.target.closest('[data-process-service]');if(proc)openProcess(proc.dataset.processService);if(e.target.matches('[data-close-process]')||e.target.id==='processModal'){$('#processModal').classList.remove('open');$('#processModal').setAttribute('aria-hidden','true')}const filter=e.target.closest('[data-service-filter]');if(filter){activeFilter=filter.dataset.serviceFilter;$$('[data-service-filter]').forEach(b=>b.classList.toggle('active',b===filter));renderServiceCatalog()}});$$('[data-add-party]').forEach(b=>b.addEventListener('click',()=>addParty(b.dataset.addParty)));$$('[data-toggle]').forEach(c=>c.addEventListener('change',()=>{$('#'+c.dataset.toggle).hidden=!c.checked}));$('#prevStep')?.addEventListener('click',()=>showStep(Math.max(1,currentStep-1)));$('#nextStep')?.addEventListener('click',()=>{if(validateStep())showStep(Math.min(5,currentStep+1))});$('#registrationForm')?.addEventListener('submit',e=>{e.preventDefault();if(validateStep()){$('#registrationSuccess').hidden=false;renderSummary()}});document.addEventListener('change',e=>{if(e.target.name==='transaction'){syncSelectedService(e.target.dataset.serviceKey);renderSummary()}});document.addEventListener('keydown',e=>{if(e.key==='Escape'){closeTrackingModal();closeLoginModal();const panel=$('.settings-panel');document.body.classList.remove('settings-open');panel?.classList.remove('open');panel?.setAttribute('aria-hidden','true')}});$('#trackingForm')?.addEventListener('submit',e=>{e.preventDefault();const input=$('#trackingCode'),err=$('[data-error-for="trackingCode"]'),result=$('#trackingResult');err.textContent='';input.classList.remove('invalid');const code=input.value.trim().toUpperCase();if(!code){err.textContent=t('tracking.required');input.classList.add('invalid');return}const record=trackingRecords[code];if(!record){err.textContent=t('tracking.notFound');input.classList.add('invalid');result.hidden=true;return}result.innerHTML=trackingHtml(record);result.hidden=false})});

document.addEventListener('DOMContentLoaded',()=>{document.addEventListener('click',e=>{if(e.target.matches('[data-close-login]')||e.target.id==='loginModal'){closeLoginModal()}});$('#publicLoginForm')?.addEventListener('submit',e=>{e.preventDefault();loggedIn=true;localStorage.setItem('settingsLoggedIn','true');applyAuthState();closeLoginModal();const panel=$('.settings-panel');panel?.classList.remove('open');document.body.classList.remove('settings-open');});});
let loginCaptchaAnswer=0;
function refreshLoginCaptcha(){const a=Math.floor(Math.random()*8)+2;const b=Math.floor(Math.random()*8)+1;loginCaptchaAnswer=a+b;const q=document.querySelector('[data-captcha-question]');const input=document.querySelector('[data-captcha-answer]');if(q)q.textContent=`${a} + ${b} = ?`;if(input)input.value='';const err=document.querySelector('[data-login-error]');if(err){err.hidden=true;err.textContent=''}}
document.addEventListener('DOMContentLoaded',()=>{refreshLoginCaptcha();document.addEventListener('click',e=>{if(e.target.closest('[data-refresh-captcha]'))refreshLoginCaptcha()});const form=document.querySelector('#publicLoginForm');form?.addEventListener('submit',e=>{const answer=Number(document.querySelector('[data-captcha-answer]')?.value||NaN);const err=document.querySelector('[data-login-error]');if(answer!==loginCaptchaAnswer){e.preventDefault();if(err){err.textContent='Captcha belum sesuai. Silakan isi jawaban yang benar.';err.hidden=false}refreshLoginCaptcha();return}},true);});

function openRegisterModal(){const login=document.querySelector('#loginModal');if(login){login.classList.remove('show-form');login.classList.remove('open');login.setAttribute('aria-hidden','true')}const modal=document.querySelector('#registerModal');if(!modal)return;document.body.classList.add('login-open');modal.classList.add('open');modal.setAttribute('aria-hidden','false');modal.classList.remove('show-form');showRegisterChoice();setTimeout(()=>modal.classList.add('show-form'),900)}
function closeRegisterModal(){const modal=document.querySelector('#registerModal');if(!modal)return;modal.classList.remove('show-form');modal.classList.remove('open');modal.setAttribute('aria-hidden','true');document.body.classList.remove('login-open')}
function showRegisterChoice(){document.querySelector('[data-register-step="choice"]')?.classList.add('active');document.querySelector('[data-register-step="choice"]')?.removeAttribute('hidden');document.querySelector('[data-register-step="form"]')?.classList.remove('active');document.querySelector('[data-register-step="form"]')?.setAttribute('hidden','hidden')}
function showRegisterForm(role){const form=document.querySelector('#publicRegisterForm');if(!form)return;form.querySelector('input[name="role"]').value=role;document.querySelector('[data-register-step="choice"]')?.classList.remove('active');document.querySelector('[data-register-step="choice"]')?.setAttribute('hidden','hidden');document.querySelector('[data-register-step="form"]')?.classList.add('active');document.querySelector('[data-register-step="form"]')?.removeAttribute('hidden');setRegisterRole(role)}
function setRegisterRole(role){const titles={user:[t('auth.userKicker'),t('auth.userTitle'),t('auth.userDesc')],staff:[t('auth.staffKicker'),t('auth.staffTitle'),t('auth.staffDesc')],notary:[t('auth.notaryKicker'),t('auth.notaryTitle'),t('auth.notaryDesc')]};document.querySelectorAll('[data-register-fields]').forEach(box=>{const active=box.dataset.registerFields===role;box.hidden=!active;box.querySelectorAll('input').forEach(input=>input.required=active)});const data=titles[role]||titles.user;const kicker=document.querySelector('[data-register-role-kicker]');const title=document.querySelector('[data-register-form-title]');const desc=document.querySelector('[data-register-form-desc]');if(kicker)kicker.textContent=data[0];if(title)title.textContent=data[1];if(desc)desc.textContent=data[2];const otp=document.querySelector('[data-otp-text]');if(otp)otp.textContent=role==='staff'?t('auth.otpStaff'):t('auth.otpDefault')}
function passwordScore(value){let score=0;if(value.length>=8)score++;if(/[A-Z]/.test(value))score++;if(/[a-z]/.test(value))score++;if(/[0-9]/.test(value))score++;if(/[^A-Za-z0-9]/.test(value))score++;return score}
function updatePasswordMeter(){const input=document.querySelector('#publicRegisterForm input[name="password"]');const meter=document.querySelector('[data-password-meter] span');const hint=document.querySelector('[data-password-hint]');if(!input||!meter||!hint)return;const score=passwordScore(input.value);meter.style.width=(score*20)+'%';meter.dataset.score=String(score);hint.textContent=score<=2?t('auth.weakPassword'):score<=4?t('auth.mediumPassword'):t('auth.strongPassword')}
document.addEventListener('DOMContentLoaded',()=>{document.addEventListener('click',e=>{const roleBtn=e.target.closest('[data-select-register-role]');if(e.target.closest('[data-register-account]')){e.preventDefault();openRegisterModal()}if(roleBtn){showRegisterForm(roleBtn.dataset.selectRegisterRole)}if(e.target.closest('[data-register-back]')){showRegisterChoice()}if(e.target.matches('[data-close-register]')||e.target.id==='registerModal'){closeRegisterModal()}if(e.target.closest('[data-back-login]')){e.preventDefault();closeRegisterModal();openLoginModal()}if(e.target.closest('[data-send-otp]')){const err=document.querySelector('[data-register-error]');if(err){err.textContent=t('auth.otpDemo');err.hidden=false}}});document.querySelector('#publicRegisterForm input[name="password"]')?.addEventListener('input',updatePasswordMeter);document.querySelector('#publicRegisterForm')?.addEventListener('submit',e=>{e.preventDefault();const role=document.querySelector('#publicRegisterForm input[name="role"]')?.value||'user';const password=document.querySelector('#publicRegisterForm input[name="password"]')?.value||'';const confirm=document.querySelector('#publicRegisterForm input[name="password_confirmation"]')?.value||'';const err=document.querySelector('[data-register-error]');if(password!==confirm){if(err){err.textContent=t('auth.passwordMismatch');err.hidden=false}return}if(passwordScore(password)<3){if(err){err.textContent=t('auth.passwordWeakSubmit');err.hidden=false}return}if(role==='notary'&&localStorage.getItem('notaryRegistered')==='true'){if(err){err.textContent=t('auth.notaryLocked');err.hidden=false}return}if(role==='notary')localStorage.setItem('notaryRegistered','true');if(err){err.textContent=t('auth.registerSuccess');err.hidden=false}});updatePasswordMeter();});